// Gugustus - NoRain (cancel rain start/stop)
if (event.getPacket() instanceof S2BPacketChangeGameState) {
  S2BPacketChangeGameState s2b =
    (S2BPacketChangeGameState) event.getPacket();
  // 1 = end rain, 2 = begin rain
  if (s2b.getGameState() == 1 || s2b.getGameState() == 2) {
    event.setCancelled(true);
  }
}
